/* Stasharr Whisparr v3: hide the old purple scene-action buttons before the
   original bundled code can flash them on screen. The module later re-enables
   the same native button only for missing sites after converting it to the
   pink "Add this site to Whisparr" action. */
(function stasharrWhisparrHideOldSceneActionButtonsEarly() {
  const STYLE_ID = 'stasharr-whisparr-hide-native-scene-action-early';
  if (document.getElementById(STYLE_ID)) return;

  const style = document.createElement('style');
  style.id = STYLE_ID;
  style.textContent = `
    .SceneCard.card button.stasharr-card-button:not(.copy-card-button):not(.stasharr-whisparr-v3-add-site-button),
    .SceneCard.card button.stasharr-button[data-stasharr-scenestatus]:not(.stasharr-whisparr-v3-add-site-button) {
      display: none !important;
      visibility: hidden !important;
      pointer-events: none !important;
    }

    .SceneCard.card button.stasharr-whisparr-v3-add-site-button {
      display: block !important;
      visibility: visible !important;
      pointer-events: auto !important;
      background-color: #ff4fa3 !important;
      color: #ffffff !important;
    }
  `;

  const target = document.head || document.documentElement;
  if (target) {
    target.appendChild(style);
  }
})();


/* Stasharr Whisparr v3: force all native add/action buttons used by this build
   to the new pink color instead of the original purple. */
(function stasharrWhisparrForcePinkNativeAddButtons() {
  const STYLE_ID = 'stasharr-whisparr-force-pink-native-add-buttons';
  if (document.getElementById(STYLE_ID)) return;

  const style = document.createElement('style');
  style.id = STYLE_ID;
  style.textContent = `
    .stasharr-button-add,
    .stasharr-card-button-add,
    button.stasharr-card-button-add,
    a.stasharr-card-button-add,
    .SceneCard.card button.stasharr-card-button-add,
    .SceneCard.card button.stasharr-whisparr-v3-add-site-button {
      background-color: #ff4fa3 !important;
      color: #ffffff !important;
    }
  `;

  const target = document.head || document.documentElement;
  if (target) target.appendChild(style);
})();

